import React from 'react';
import { AlertTriangle, CheckCircle2 } from 'lucide-react';
import { formatCurrency } from '../utils/format';

export default function FindingsBadge({ findings = [], savings = 0, compact = false }) {
  if (!findings.length) {
    return (
      <span className="findings-badge findings-badge--clear" title="No open findings">
        <CheckCircle2 size={12} />
        {!compact && 'Clear'}
      </span>
    );
  }

  const critical = findings.filter((f) => f.severity === 'CRITICAL').length;
  const high = findings.filter((f) => f.severity === 'HIGH').length;
  const tone = critical > 0 ? 'critical' : high > 0 ? 'high' : 'medium';

  return (
    <span className={`findings-badge findings-badge--${tone}`} title={`${findings.length} open finding(s)`}>
      <AlertTriangle size={12} />
      <span>{findings.length}</span>
      {!compact && savings > 0 && (
        <span className="findings-badge__savings">
          {formatCurrency(savings, { currency: 'CAD', decimals: 0 })}
        </span>
      )}
    </span>
  );
}
