import React, { useContext, useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import PageHeader from '../components/PageHeader';
import AssetIcon from '../components/AssetIcon';
import SyncButton from '../components/SyncButton';
import FetchFromAzureButton from '../components/FetchFromAzureButton';
import AdminOnly from '../components/AdminOnly';
import ActionMessage from '../components/ActionMessage';
import useResourceSync from '../hooks/useResourceSync';
import useResourceSource from '../hooks/useResourceSource';
import { PAGE_ICONS } from '../config/assetIcons';
import { AppCtx } from '../App';
import { fetchAKS } from '../api/azure';
import FindingsBadge from '../components/FindingsBadge';
import ResourceInsightDrawer from '../components/ResourceInsightDrawer';
import useFindingsIndex from '../hooks/useFindingsIndex';
import { formatCurrency } from '../utils/format';
import { QueryErrorState, SubscriptionRequired } from '../components/QueryStates';
import { dedupeAksClusters, normalizeAksCluster } from '../utils/aksNormalize';
import { toDisplayText } from '../utils/formatDisplay';

const STATE_COLOR = { Running: 'var(--success)', Stopped: 'var(--warning)', Failed: 'var(--danger)', Creating: 'var(--accent)', Succeeded: 'var(--success)' };

export default function AKSClusters() {
  const { subscription, billingCurrency } = useContext(AppCtx);
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState(null);
  const currency = billingCurrency || 'CAD';
  const { byResourceId, savingsByResource } = useFindingsIndex(subscription);
  const { dataSource, isLive, fetchFromAzure, resetToDatabase, isAdmin } = useResourceSource();

  const { sync, syncing, message: syncMsg } = useResourceSync({
    subscription,
    invalidateKeys: [['aks', subscription], ['resource-counts', subscription], ['findings-index', subscription]],
  });

  const { data: clusters = [], isLoading, isError, error, refetch, isFetching } = useQuery({
    queryKey: ['aks', subscription, dataSource],
    queryFn: () => fetchAKS({ subscription_id: subscription, source: dataSource }),
    enabled: !!subscription,
    staleTime: dataSource === 'db' ? 5 * 60_000 : 0,
  });

  const normalizedClusters = useMemo(
    () => dedupeAksClusters(clusters).map(normalizeAksCluster),
    [clusters],
  );

  const handleSync = async () => {
    try {
      resetToDatabase();
      await sync();
      await refetch();
    } catch {
      /* syncMsg */
    }
  };

  const handleRefresh = () => {
    resetToDatabase();
    refetch();
  };

  const filtered = normalizedClusters.filter((c) => {
    if (!search) return true;
    const q = search.toLowerCase();
    return (c.name || '').toLowerCase().includes(q)
      || (c.location || '').toLowerCase().includes(q)
      || (c.resourceGroup || '').toLowerCase().includes(q);
  });

  const running = normalizedClusters.filter((c) => c._state === 'Running' || c._state === 'Succeeded').length;
  const stopped = normalizedClusters.filter((c) => c._state === 'Stopped').length;
  const totalNodes = normalizedClusters.reduce((sum, c) => sum + c._nodeCount, 0);
  const versions = [...new Set(normalizedClusters.map((c) => c._version).filter((v) => v && v !== '—'))];

  const selectedCluster = selected ? normalizeAksCluster(selected) : null;
  const selectedFindings = selected
    ? (byResourceId.get((selected.id || '').toLowerCase()) || [])
    : [];
  const rid = (c) => (c.id || '').toLowerCase();
  const monthlyCost = (c) => c.monthlyCostUsd ?? c.monthly_cost_usd ?? 0;

  return (
    <div>
      <PageHeader
        title="AKS clusters"
        iconSrc={PAGE_ICONS.aks}
        subtitle={subscription ? `${isLive ? 'live from Azure' : 'from database'} · ${normalizedClusters.length} clusters` : 'Select a subscription'}
      >
        <input placeholder="Search name, location…" value={search} onChange={e => setSearch(e.target.value)} style={{ width: 240 }} />
        <ActionMessage message={syncMsg} />
        <AdminOnly>
          <SyncButton onClick={handleSync} syncing={syncing} disabled={!subscription} />
          <FetchFromAzureButton onClick={fetchFromAzure} loading={isFetching && isLive} disabled={!subscription} active={isLive} />
        </AdminOnly>
        <button type="button" className="btn btn-secondary" onClick={handleRefresh} disabled={!subscription || isFetching}>Refresh</button>
      </PageHeader>

      {!subscription && <SubscriptionRequired />}
      {subscription && isError && <QueryErrorState error={error} onRetry={handleRefresh} title="Could not load AKS clusters" />}

      {subscription && !isError && (
      <>
      <div className="grid-4" style={{ marginBottom: '1.5rem' }}>
        <div className="stat-card accent">
          <AssetIcon src={PAGE_ICONS.aks} size={22} className="stat-card__icon" alt="" />
          <div className="stat-label">Total clusters</div><div className="stat-value">{normalizedClusters.length}</div><div className="stat-sub">{running} running</div>
        </div>
        <div className="stat-card warning">
          <AssetIcon src={PAGE_ICONS.kubernetes} size={22} className="stat-card__icon" alt="" />
          <div className="stat-label">Stopped</div><div className="stat-value">{stopped}</div><div className="stat-sub">Not incurring compute</div>
        </div>
        <div className="stat-card success">
          <AssetIcon src={PAGE_ICONS.k8sNode} size={22} className="stat-card__icon" alt="" />
          <div className="stat-label">Total nodes</div><div className="stat-value">{totalNodes.toLocaleString()}</div><div className="stat-sub">Across all pools</div>
        </div>
        <div className="stat-card purple">
          <AssetIcon src={PAGE_ICONS.nodepool} size={22} className="stat-card__icon" alt="" />
          <div className="stat-label">K8s versions</div><div className="stat-value">{versions.length}</div><div className="stat-sub">{versions[0] || '—'} (latest in use)</div>
        </div>
      </div>

      <div className="card">
        {isLoading ? <div className="empty-state"><div className="spin" /></div> :
         filtered.length === 0 ? (
          <div className="empty-state">
            <AssetIcon src={PAGE_ICONS.aks} size={32} alt="" style={{ opacity: 0.45 }} />
            <p>{isAdmin ? 'No AKS clusters in the database. Run Sync from Azure to save inventory, or Fetch from Azure for a live preview.' : 'No AKS clusters in the database yet.'}</p>
            <AdminOnly>
              <div style={{ display: 'flex', gap: 8, justifyContent: 'center', marginTop: '1rem', flexWrap: 'wrap' }}>
                <SyncButton onClick={handleSync} syncing={syncing} disabled={!subscription} className="btn btn-primary" />
                <FetchFromAzureButton onClick={fetchFromAzure} disabled={!subscription} className="btn btn-secondary" />
              </div>
            </AdminOnly>
          </div>
         ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Name</th><th>Resource group</th><th>Version</th><th>Location</th>
                  <th>Node pools</th><th>Nodes</th><th>State</th>
                  <th>MTD cost (CAD)</th><th>Analysis</th><th>SKU</th><th>Network</th><th>Tags</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((c) => {
                  const clusterRid = rid(c);
                  const findings = byResourceId.get(clusterRid) || [];
                  const cost = monthlyCost(c);
                  return (
                    <tr key={`${c.id || c.name}-${c.resourceGroup || ''}`} className="resource-table__row" onClick={() => setSelected(c)}>
                      <td>
                        <span className="icon-inline">
                          <AssetIcon src={PAGE_ICONS.aks} size={18} alt="" />
                          <span className="resource-name">{c.name}</span>
                        </span>
                      </td>
                      <td style={{ fontSize: '0.8rem', color: 'var(--text2)' }}>{c.resourceGroup || '—'}</td>
                      <td style={{ fontFamily: 'monospace', fontSize: '0.8rem' }}>{c._version}</td>
                      <td>{c.location}</td>
                      <td>{c._pools.length}</td>
                      <td>{c._nodeCount}</td>
                      <td><span style={{ color: STATE_COLOR[c._state] || 'var(--text2)', fontWeight: 600, fontSize: '0.8rem' }}>● {c._state}</span></td>
                      <td>{cost > 0 ? formatCurrency(cost, { currency }) : '—'}</td>
                      <td><FindingsBadge findings={findings} savings={savingsByResource.get(clusterRid) || 0} /></td>
                      <td style={{ fontSize: '0.78rem' }}>{c._sku}</td>
                      <td style={{ fontSize: '0.78rem' }}>{c._network}</td>
                      <td style={{ fontSize: '0.75rem', color: 'var(--text2)' }}>
                        {Object.entries(c.tags || {}).slice(0, 2).map(([k, v]) => (
                          <span key={k} className="tag" style={{ marginRight: 4 }}>{k}: {toDisplayText(v)}</span>
                        ))}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>


      <ResourceInsightDrawer
        resource={selectedCluster || selected}
        findings={selectedFindings}
        onClose={() => setSelected(null)}
        title="AKS cluster"
        iconKey={PAGE_ICONS.aks}
      />
      </>
      )}
    </div>
  );
}
